        { const __m512d tr = x0_re;
          x0_re = _mm512_fmadd_pd(x0_re,tw0_re,_mm512_mul_pd(x0_im,tw0_im));
          x0_im = _mm512_fmsub_pd(x0_im,tw0_re,_mm512_mul_pd(tr,tw0_im)); }
        x1_re = LD(&rio_re[m+4*ios]);
        x1_im = LD(&rio_im[m+4*ios]);
        { const __m512d tr = x1_re;
          x1_re = _mm512_fmadd_pd(x1_re,tw3_re,_mm512_mul_pd(x1_im,tw3_im));
          x1_im = _mm512_fmsub_pd(x1_im,tw3_re,_mm512_mul_pd(tr,tw3_im)); }
        x2_re = LD(&rio_re[m+7*ios]);
        x2_im = LD(&rio_im[m+7*ios]);
        { const __m512d tr = x2_re;
          x2_re = _mm512_fmadd_pd(x2_re,tw6_re,_mm512_mul_pd(x2_im,tw6_im));
          x2_im = _mm512_fmsub_pd(x2_im,tw6_re,_mm512_mul_pd(tr,tw6_im)); }
