        _mm512_store_pd(&a_spill_re[8*8], a_x0_re);
        _mm512_store_pd(&a_spill_im[8*8], a_x0_im);
        _mm512_store_pd(&a_spill_re[9*8], a_x1_re);
        _mm512_store_pd(&a_spill_im[9*8], a_x1_im);
        _mm512_store_pd(&a_spill_re[10*8], a_x2_re);
        _mm512_store_pd(&a_spill_im[10*8], a_x2_im);
        _mm512_store_pd(&a_spill_re[11*8], a_x3_re);
        _mm512_store_pd(&a_spill_im[11*8], a_x3_im);

        /* PASS 2: 4x radix-3 columns */

        /* column k1=0 */
        a_x0_re = _mm512_load_pd(&a_spill_re[0*8]);
