        a_x1_re = _mm512_load_pd(&a_spill_re[4*8]);
        a_x1_im = _mm512_load_pd(&a_spill_im[4*8]);
        a_x2_re = _mm512_load_pd(&a_spill_re[8*8]);
        a_x2_im = _mm512_load_pd(&a_spill_im[8*8]);

        /* radix-3 k1=0 [bwd] */
        {
        __m512d sr=_mm512_add_pd(a_x1_re,a_x2_re), si=_mm512_add_pd(a_x1_im,a_x2_im);
        __m512d dr=_mm512_sub_pd(a_x1_re,a_x2_re), di=_mm512_sub_pd(a_x1_im,a_x2_im);
        __m512d Rr=_mm512_fnmadd_pd(KHALF,sr,a_x0_re), Ri=_mm512_fnmadd_pd(KHALF,si,a_x0_im);
        a_x0_re=_mm512_add_pd(a_x0_re,sr); a_x0_im=_mm512_add_pd(a_x0_im,si);
        a_x1_re=_mm512_fnmadd_pd(KS,di,Rr); a_x1_im=_mm512_fmadd_pd(KS,dr,Ri);
        a_x2_re=_mm512_fmadd_pd(KS,di,Rr); a_x2_im=_mm512_fnmadd_pd(KS,dr,Ri);
        }

        ST(&rio_re[m+0*ios], a_x0_re);
        ST(&rio_im[m+0*ios], a_x0_im);
        ST(&rio_re[m+4*ios], a_x1_re);
        ST(&rio_im[m+4*ios], a_x1_im);
        ST(&rio_re[m+8*ios], a_x2_re);
        ST(&rio_im[m+8*ios], a_x2_im);

        /* column k1=1 */
        a_x0_re = _mm512_load_pd(&a_spill_re[1*8]);
        a_x0_im = _mm512_load_pd(&a_spill_im[1*8]);
        a_x1_re = _mm512_load_pd(&a_spill_re[5*8]);
        a_x1_im = _mm512_load_pd(&a_spill_im[5*8]);
        a_x2_re = _mm512_load_pd(&a_spill_re[9*8]);
        a_x2_im = _mm512_load_pd(&a_spill_im[9*8]);

        { __m512d a_tr = a_x1_re;
          a_x1_re = _mm512_fmadd_pd(a_x1_re,tw_W12_1_re,_mm512_mul_pd(a_x1_im,tw_W12_1_im));
          a_x1_im = _mm512_fmsub_pd(a_x1_im,tw_W12_1_re,_mm512_mul_pd(a_tr,tw_W12_1_im)); }
        { __m512d a_tr = a_x2_re;
          a_x2_re = _mm512_fmadd_pd(a_x2_re,tw_W12_2_re,_mm512_mul_pd(a_x2_im,tw_W12_2_im));
          a_x2_im = _mm512_fmsub_pd(a_x2_im,tw_W12_2_re,_mm512_mul_pd(a_tr,tw_W12_2_im)); }

        /* radix-3 k1=1 [bwd] */
        {
        __m512d sr=_mm512_add_pd(a_x1_re,a_x2_re), si=_mm512_add_pd(a_x1_im,a_x2_im);
        __m512d dr=_mm512_sub_pd(a_x1_re,a_x2_re), di=_mm512_sub_pd(a_x1_im,a_x2_im);
        __m512d Rr=_mm512_fnmadd_pd(KHALF,sr,a_x0_re), Ri=_mm512_fnmadd_pd(KHALF,si,a_x0_im);
        a_x0_re=_mm512_add_pd(a_x0_re,sr); a_x0_im=_mm512_add_pd(a_x0_im,si);
        a_x1_re=_mm512_fnmadd_pd(KS,di,Rr); a_x1_im=_mm512_fmadd_pd(KS,dr,Ri);
        a_x2_re=_mm512_fmadd_pd(KS,di,Rr); a_x2_im=_mm512_fnmadd_pd(KS,dr,Ri);
        }

        ST(&rio_re[m+1*ios], a_x0_re);
        ST(&rio_im[m+1*ios], a_x0_im);
        ST(&rio_re[m+5*ios], a_x1_re);
        ST(&rio_im[m+5*ios], a_x1_im);
        ST(&rio_re[m+9*ios], a_x2_re);
        ST(&rio_im[m+9*ios], a_x2_im);

        /* column k1=2 */
        a_x0_re = _mm512_load_pd(&a_spill_re[2*8]);
        a_x0_im = _mm512_load_pd(&a_spill_im[2*8]);
        a_x1_re = _mm512_load_pd(&a_spill_re[6*8]);
        a_x1_im = _mm512_load_pd(&a_spill_im[6*8]);
        a_x2_re = _mm512_load_pd(&a_spill_re[10*8]);
        a_x2_im = _mm512_load_pd(&a_spill_im[10*8]);

        { __m512d a_tr = a_x1_re;
          a_x1_re = _mm512_fmadd_pd(a_x1_re,tw_W12_2_re,_mm512_mul_pd(a_x1_im,tw_W12_2_im));
          a_x1_im = _mm512_fmsub_pd(a_x1_im,tw_W12_2_re,_mm512_mul_pd(a_tr,tw_W12_2_im)); }
        { __m512d a_tr = a_x2_re;
          a_x2_re = _mm512_fmadd_pd(a_x2_re,tw_W12_4_re,_mm512_mul_pd(a_x2_im,tw_W12_4_im));
          a_x2_im = _mm512_fmsub_pd(a_x2_im,tw_W12_4_re,_mm512_mul_pd(a_tr,tw_W12_4_im)); }

        /* radix-3 k1=2 [bwd] */
        {
        __m512d sr=_mm512_add_pd(a_x1_re,a_x2_re), si=_mm512_add_pd(a_x1_im,a_x2_im);
        __m512d dr=_mm512_sub_pd(a_x1_re,a_x2_re), di=_mm512_sub_pd(a_x1_im,a_x2_im);
        __m512d Rr=_mm512_fnmadd_pd(KHALF,sr,a_x0_re), Ri=_mm512_fnmadd_pd(KHALF,si,a_x0_im);
        a_x0_re=_mm512_add_pd(a_x0_re,sr); a_x0_im=_mm512_add_pd(a_x0_im,si);
        a_x1_re=_mm512_fnmadd_pd(KS,di,Rr); a_x1_im=_mm512_fmadd_pd(KS,dr,Ri);
        a_x2_re=_mm512_fmadd_pd(KS,di,Rr); a_x2_im=_mm512_fnmadd_pd(KS,dr,Ri);
        }

        ST(&rio_re[m+2*ios], a_x0_re);
        ST(&rio_im[m+2*ios], a_x0_im);
        ST(&rio_re[m+6*ios], a_x1_re);
        ST(&rio_im[m+6*ios], a_x1_im);
