        ST(&rio_im[m+10*ios], a_x2_im);

        /* column k1=3 */
        a_x0_re = _mm512_load_pd(&a_spill_re[3*8]);
        a_x0_im = _mm512_load_pd(&a_spill_im[3*8]);
