        __m512d dr=_mm512_sub_pd(b_x0_re,b_x2_re), di=_mm512_sub_pd(b_x0_im,b_x2_im);
        __m512d b_tr=_mm512_add_pd(b_x1_re,b_x3_re), ti=_mm512_add_pd(b_x1_im,b_x3_im);
        __m512d ur=_mm512_sub_pd(b_x1_re,b_x3_re), ui=_mm512_sub_pd(b_x1_im,b_x3_im);
        b_x0_re=_mm512_add_pd(sr,b_tr); b_x0_im=_mm512_add_pd(si,ti);
        b_x2_re=_mm512_sub_pd(sr,b_tr); b_x2_im=_mm512_sub_pd(si,ti);
        b_x1_re=_mm512_sub_pd(dr,ui); b_x1_im=_mm512_add_pd(di,ur);
        b_x3_re=_mm512_add_pd(dr,ui); b_x3_im=_mm512_sub_pd(di,ur);
