        _mm512_store_pd(&b_spill_im[5*8], b_x1_im);
        _mm512_store_pd(&b_spill_re[6*8], b_x2_re);
        _mm512_store_pd(&b_spill_im[6*8], b_x2_im);
        _mm512_store_pd(&b_spill_re[7*8], b_x3_re);
        _mm512_store_pd(&b_spill_im[7*8], b_x3_im);

        /* sub-FFT n2=2 */
        b_x0_re = LD(&rio_re[(m+8)+2*ios]);
        b_x0_im = LD(&rio_im[(m+8)+2*ios]);
        { const __m512d b_wr = LD(&W_re[1*me+(m+8)]);
          const __m512d b_wi = LD(&W_im[1*me+(m+8)]);
          const __m512d b_tr = b_x0_re;
          b_x0_re = _mm512_fmadd_pd(b_x0_re,b_wr,_mm512_mul_pd(b_x0_im,b_wi));
          b_x0_im = _mm512_fmsub_pd(b_x0_im,b_wr,_mm512_mul_pd(b_tr,b_wi)); }
        b_x1_re = LD(&rio_re[(m+8)+5*ios]);
        b_x1_im = LD(&rio_im[(m+8)+5*ios]);
        { const __m512d b_wr = LD(&W_re[4*me+(m+8)]);
          const __m512d b_wi = LD(&W_im[4*me+(m+8)]);
          const __m512d b_tr = b_x1_re;
          b_x1_re = _mm512_fmadd_pd(b_x1_re,b_wr,_mm512_mul_pd(b_x1_im,b_wi));
          b_x1_im = _mm512_fmsub_pd(b_x1_im,b_wr,_mm512_mul_pd(b_tr,b_wi)); }
        b_x2_re = LD(&rio_re[(m+8)+8*ios]);
        b_x2_im = LD(&rio_im[(m+8)+8*ios]);
