        _mm512_store_pd(&b_spill_re[8*8], b_x0_re);
        _mm512_store_pd(&b_spill_im[8*8], b_x0_im);
        _mm512_store_pd(&b_spill_re[9*8], b_x1_re);
        _mm512_store_pd(&b_spill_im[9*8], b_x1_im);
        _mm512_store_pd(&b_spill_re[10*8], b_x2_re);
        _mm512_store_pd(&b_spill_im[10*8], b_x2_im);
        _mm512_store_pd(&b_spill_re[11*8], b_x3_re);
        _mm512_store_pd(&b_spill_im[11*8], b_x3_im);

        /* PASS 2: 4x radix-3 columns */

        /* column k1=0 */
        b_x0_re = _mm512_load_pd(&b_spill_re[0*8]);
        b_x0_im = _mm512_load_pd(&b_spill_im[0*8]);
        b_x1_re = _mm512_load_pd(&b_spill_re[4*8]);
        b_x1_im = _mm512_load_pd(&b_spill_im[4*8]);
        b_x2_re = _mm512_load_pd(&b_spill_re[8*8]);
        b_x2_im = _mm512_load_pd(&b_spill_im[8*8]);

        /* radix-3 k1=0 [bwd] */
        {
        __m512d sr=_mm512_add_pd(b_x1_re,b_x2_re), si=_mm512_add_pd(b_x1_im,b_x2_im);
        __m512d dr=_mm512_sub_pd(b_x1_re,b_x2_re), di=_mm512_sub_pd(b_x1_im,b_x2_im);
        __m512d Rr=_mm512_fnmadd_pd(KHALF,sr,b_x0_re), Ri=_mm512_fnmadd_pd(KHALF,si,b_x0_im);
        b_x0_re=_mm512_add_pd(b_x0_re,sr); b_x0_im=_mm512_add_pd(b_x0_im,si);
        b_x1_re=_mm512_fnmadd_pd(KS,di,Rr); b_x1_im=_mm512_fmadd_pd(KS,dr,Ri);
        b_x2_re=_mm512_fmadd_pd(KS,di,Rr); b_x2_im=_mm512_fnmadd_pd(KS,dr,Ri);
        }

        ST(&rio_re[(m+8)+0*ios], b_x0_re);
        ST(&rio_im[(m+8)+0*ios], b_x0_im);
        ST(&rio_re[(m+8)+4*ios], b_x1_re);
        ST(&rio_im[(m+8)+4*ios], b_x1_im);
        ST(&rio_re[(m+8)+8*ios], b_x2_re);
        ST(&rio_im[(m+8)+8*ios], b_x2_im);

        /* column k1=1 */
        b_x0_re = _mm512_load_pd(&b_spill_re[1*8]);
        b_x0_im = _mm512_load_pd(&b_spill_im[1*8]);
        b_x1_re = _mm512_load_pd(&b_spill_re[5*8]);
        b_x1_im = _mm512_load_pd(&b_spill_im[5*8]);
        b_x2_re = _mm512_load_pd(&b_spill_re[9*8]);
        b_x2_im = _mm512_load_pd(&b_spill_im[9*8]);

        { __m512d b_tr = b_x1_re;
          b_x1_re = _mm512_fmadd_pd(b_x1_re,tw_W12_1_re,_mm512_mul_pd(b_x1_im,tw_W12_1_im));
          b_x1_im = _mm512_fmsub_pd(b_x1_im,tw_W12_1_re,_mm512_mul_pd(b_tr,tw_W12_1_im)); }
        { __m512d b_tr = b_x2_re;
          b_x2_re = _mm512_fmadd_pd(b_x2_re,tw_W12_2_re,_mm512_mul_pd(b_x2_im,tw_W12_2_im));
          b_x2_im = _mm512_fmsub_pd(b_x2_im,tw_W12_2_re,_mm512_mul_pd(b_tr,tw_W12_2_im)); }

