        ST(&rio_re[m+3*ios], x0_re);
        ST(&rio_im[m+3*ios], x0_im);
        ST(&rio_re[m+7*ios], x1_re);
        ST(&rio_im[m+7*ios], x1_im);
        ST(&rio_re[m+11*ios], x2_re);
