        w3r = _mm512_fmsub_pd(w1r,w2r,_mm512_mul_pd(w1i,w2i));
        w3i = _mm512_fmadd_pd(w1r,w2i,_mm512_mul_pd(w1i,w2r));
        __m512d w4r, w4i;
        w4r = _mm512_fmsub_pd(w2r,w2r,_mm512_mul_pd(w2i,w2i));
        w4i = _mm512_fmadd_pd(w2r,w2i,_mm512_mul_pd(w2i,w2r));
        __m512d w5r, w5i;
        w5r = _mm512_fmsub_pd(w1r,w4r,_mm512_mul_pd(w1i,w4i));
        w5i = _mm512_fmadd_pd(w1r,w4i,_mm512_mul_pd(w1i,w4r));
        __m512d w6r, w6i;
        w6r = _mm512_fmsub_pd(w3r,w3r,_mm512_mul_pd(w3i,w3i));
